// Set at different scopes
pm.globals.set('host', 'api.example.com');
pm.collectionVariables.set('version', 'v2');
pm.environment.set('token', 'abc123');
pm.variables.set('requestId', 'local-only'); // local scope

// Read resolved value (narrowest wins)
console.log(pm.variables.get('token'));

pm.test('response is JSON with id', function () {
  pm.response.to.have.status(200);
  const body = pm.response.json();
  pm.expect(body).to.have.property('id');
});

console.log('Time:', pm.response.responseTime + 'ms');

// In login request Tests tab:
const token = pm.response.json().accessToken;
pm.environment.set('authToken', token);

// In next request Authorization header:
// Authorization: Bearer {{authToken}}

// Capture created id for later GET
pm.environment.set('userId', pm.response.json().id);

pm.test('status code is 200', () => pm.response.to.have.status(200));

pm.test('has JSON content-type', () => {
  pm.expect(pm.response.headers.get('Content-Type')).to.include('application/json');
});

pm.test('response time < 500ms', () => {
  pm.expect(pm.response.responseTime).to.be.below(500);
});

// In request body:
// {
//   "email": "{{$randomEmail}}",
//   "id": "{{$guid}}",
//   "createdAt": {{$timestamp}}
// }

// In a script:
const email = pm.variables.replaceIn('{{$randomEmail}}');
pm.environment.set('newEmail', email);

// Bearer header injected by Postman:
// Authorization: Bearer {{authToken}}

// Basic auth manual encode in a pre-request script:
const creds = btoa('user:pass');
pm.request.headers.add({ key: 'Authorization', value: 'Basic ' + creds });

// Access the current iteration inside scripts:
console.log('Iteration:', pm.info.iteration);
console.log('Request name:', pm.info.requestName);

// Conditionally skip logic on first iteration
if (pm.info.iteration === 0) {
  pm.environment.set('setupDone', 'true');
}

// data.json: [{ "user": "a", "expected": 200 }, { "user": "b", "expected": 404 }]

// In request body: { "username": "{{user}}" }

// In Tests tab:
const expected = Number(pm.iterationData.get('expected'));
pm.test('status matches data row', () => {
  pm.response.to.have.status(expected);
});

// Read the active environment name in a script:
console.log('Active env:', pm.environment.name);

// Guard against running destructive tests in prod
if (pm.environment.name === 'prod') {
  throw new Error('Refusing to run this collection against prod');
}

// Monitors run your existing test scripts, e.g.:
pm.test('health endpoint up', () => {
  pm.response.to.have.status(200);
  pm.expect(pm.response.json().status).to.eql('ok');
});

pm.test('latency under SLA', () => {
  pm.expect(pm.response.responseTime).to.be.below(800);
});

pm.sendRequest({
  url: pm.environment.get('authUrl') + '/token',
  method: 'POST',
  header: { 'Content-Type': 'application/json' },
  body: { mode: 'raw', raw: JSON.stringify({ grant_type: 'client_credentials' }) }
}, function (err, res) {
  if (err) { console.error(err); return; }
  pm.environment.set('authToken', res.json().access_token);
});

const schema = {
  type: 'object',
  required: ['id', 'email'],
  properties: {
    id: { type: 'number' },
    email: { type: 'string' }
  }
};

pm.test('body matches schema', () => {
  pm.expect(pm.response.json()).to.be.jsonSchema(schema);
});

// Read a cookie value in Tests:
const sessionId = pm.cookies.get('sessionId');
console.log('session:', sessionId);

// Programmatically set a cookie via the jar:
const jar = pm.cookies.jar();
jar.set('https://api.example.com', 'consent', 'true', (err) => {
  if (err) console.error(err);
});

// Body (GraphQL mode) query:
// query GetUser($id: ID!) { user(id: $id) { id name } }
// Variables: { "id": "{{userId}}" }

pm.test('no GraphQL errors', () => {
  const body = pm.response.json();
  pm.expect(body.errors).to.be.undefined;
  pm.expect(body.data.user).to.have.property('id');
});

const template = `
<table>
  <tr><th>Name</th><th>Email</th></tr>
  {{#each users}}
    <tr><td>{{name}}</td><td>{{email}}</td></tr>
  {{/each}}
</table>`;

pm.visualizer.set(template, { users: pm.response.json() });
